const employees = $('Aggregate').item.json.data;

// ===== ONBOARDING =====
const total = employees.length;
const active = employees.filter(e => e['Status'] === 'Active').length;
const inProgress = employees.filter(e => e['Onboarding_Status'] === 'In Progress').length;
const completed = employees.filter(e => e['Onboarding_Status'] === 'Completed').length;
const pending = employees.filter(e => e['Onboarding_Status'] === 'Pending').length;

// ===== GRIEVANCE =====
const grievanceYes = employees.filter(e => e['Grievance'] === 'Yes').length;
const grievanceNo = employees.filter(e => e['Grievance'] === 'No').length;
const openIssues = employees.filter(e => e['Issue_Status'] === 'Open').length;
const closedIssues = employees.filter(e => e['Issue_Status'] === 'Closed').length;

// ===== PRIORITY =====
const highP = employees.filter(e => (e['Priority']||'').toLowerCase() === 'high').length;
const mediumP = employees.filter(e => (e['Priority']||'').toLowerCase() === 'medium').length;
const lowP = employees.filter(e => (e['Priority']||'').toLowerCase() === 'low').length;

// ===== ISSUE TYPE WISE =====
const issueMap = {};
employees.forEach(e => {
  const type = e['Issue_Type'] || 'NA';
  if (type === 'NA' || !e['Grievance'] || e['Grievance'] !== 'Yes') return;
  if (!issueMap[type]) issueMap[type] = { high: 0, medium: 0, low: 0, total: 0 };
  issueMap[type].total++;
  const p = (e['Priority']||'').toLowerCase();
  if (p === 'high') issueMap[type].high++;
  else if (p === 'medium') issueMap[type].medium++;
  else if (p === 'low') issueMap[type].low++;
});

// ===== DEPT WISE =====
const deptMap = {};
employees.forEach(e => {
  const dept = e['Department'] || 'Unknown';
  if (!deptMap[dept]) deptMap[dept] = { total: 0, active: 0, inProgress: 0, completed: 0, pending: 0, grievance: 0, open: 0 };
  deptMap[dept].total++;
  if (e['Status'] === 'Active') deptMap[dept].active++;
  if (e['Onboarding_Status'] === 'In Progress') deptMap[dept].inProgress++;
  if (e['Onboarding_Status'] === 'Completed') deptMap[dept].completed++;
  if (e['Onboarding_Status'] === 'Pending') deptMap[dept].pending++;
  if (e['Grievance'] === 'Yes') deptMap[dept].grievance++;
  if (e['Issue_Status'] === 'Open') deptMap[dept].open++;
});

const sheetId = '17D65gxcTNocEAt-tlFxH8jZZg2hBF9irNt83Xmgb5BA';
const dashboardLink = `https://docs.google.com/spreadsheets/d/${sheetId}`;

// ===== HELPERS =====
const maxOnboard = Math.max(active, inProgress, completed, pending, 1);
const maxGriev = Math.max(grievanceYes, grievanceNo, openIssues, closedIssues, 1);

const bar = (val, color, label, maxV) => `
  <div style="margin:10px 0;">
    <div style="display:flex;align-items:center;gap:10px;">
      <div style="width:110px;font-size:12px;color:#94a3b8;">${label}</div>
      <div style="background:${color};height:26px;width:${Math.round((val/maxV)*240)}px;
                  border-radius:6px;min-width:28px;"></div>
      <div style="font-weight:bold;color:white;font-size:15px;">${val}</div>
    </div>
  </div>`;

const pct = (v, tot) => Math.round((v / Math.max(tot, 1)) * 100);

// ===== GRIEVANCE TABLE ROWS =====
const issueRows = Object.entries(issueMap)
  .sort((a,b) => b[1].total - a[1].total)
  .map(([type, d]) => `
  <tr>
    <td style="padding:9px 12px;color:#e2e8f0;border-bottom:1px solid #334155;font-size:13px;">${type}</td>
    <td style="padding:9px 12px;text-align:center;border-bottom:1px solid #334155;">
      <span style="background:#ff4d4d33;color:#ff4d4d;padding:3px 10px;border-radius:20px;font-weight:bold;font-size:13px;">${d.high}</span>
    </td>
    <td style="padding:9px 12px;text-align:center;border-bottom:1px solid #334155;">
      <span style="background:#f5a62333;color:#f5a623;padding:3px 10px;border-radius:20px;font-weight:bold;font-size:13px;">${d.medium}</span>
    </td>
    <td style="padding:9px 12px;text-align:center;border-bottom:1px solid #334155;">
      <span style="background:#7ed32133;color:#7ed321;padding:3px 10px;border-radius:20px;font-weight:bold;font-size:13px;">${d.low}</span>
    </td>
    <td style="padding:9px 12px;text-align:center;border-bottom:1px solid #334155;color:white;font-weight:bold;">${d.total}</td>
  </tr>`).join('');

// ===== DEPT TABLE ROWS =====
const deptRows = Object.entries(deptMap)
  .sort((a,b) => b[1].total - a[1].total)
  .map(([dept, d]) => `
  <tr>
    <td style="padding:8px 10px;color:#e2e8f0;border-bottom:1px solid #334155;font-size:12px;">${dept}</td>
    <td style="padding:8px 10px;text-align:center;border-bottom:1px solid #334155;color:#00c6ff;font-weight:bold;">${d.total}</td>
    <td style="padding:8px 10px;text-align:center;border-bottom:1px solid #334155;color:#7ed321;font-weight:bold;">${d.active}</td>
    <td style="padding:8px 10px;text-align:center;border-bottom:1px solid #334155;color:#f5a623;font-weight:bold;">${d.inProgress}</td>
    <td style="padding:8px 10px;text-align:center;border-bottom:1px solid #334155;color:#06b6d4;font-weight:bold;">${d.completed}</td>
    <td style="padding:8px 10px;text-align:center;border-bottom:1px solid #334155;color:#ff4d4d;font-weight:bold;">${d.grievance}</td>
  </tr>`).join('');

// ===== HTML EMAIL =====
const html = `
<div style="font-family:'Segoe UI',sans-serif;background:#0f172a;padding:20px;color:white;max-width:650px;margin:0 auto;">

  <!-- HEADER -->
  <div style="background:linear-gradient(135deg,#00c6ff,#7f00ff);padding:26px;border-radius:16px;margin-bottom:20px;">
    <h1 style="margin:0;font-size:21px;">📊 PeopleOS HR Dashboard</h1>
    <p style="margin:6px 0 0;opacity:0.85;font-size:13px;">Daily Report • ${new Date().toDateString()}</p>
  </div>

  <!-- ========== SECTION 1: ONBOARDING ========== -->
  <div style="background:#1e293b;padding:20px;border-radius:16px;margin-bottom:20px;border-left:4px solid #00c6ff;">
    <h2 style="margin:0 0 16px;font-size:16px;color:#00c6ff;">👥 Onboarding Overview</h2>

    <!-- KPI -->
    <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:18px;">
      <div style="flex:1;min-width:80px;background:#0f172a;padding:14px 8px;border-radius:12px;text-align:center;border-top:3px solid #00c6ff;">
        <div style="font-size:24px;font-weight:bold;color:#00c6ff;">${total}</div>
        <div style="font-size:11px;color:#94a3b8;">Total</div>
      </div>
      <div style="flex:1;min-width:80px;background:#0f172a;padding:14px 8px;border-radius:12px;text-align:center;border-top:3px solid #7ed321;">
        <div style="font-size:24px;font-weight:bold;color:#7ed321;">${active}</div>
        <div style="font-size:11px;color:#94a3b8;">✅ Active</div>
      </div>
      <div style="flex:1;min-width:80px;background:#0f172a;padding:14px 8px;border-radius:12px;text-align:center;border-top:3px solid #f5a623;">
        <div style="font-size:24px;font-weight:bold;color:#f5a623;">${inProgress}</div>
        <div style="font-size:11px;color:#94a3b8;">🚀 In Progress</div>
      </div>
      <div style="flex:1;min-width:80px;background:#0f172a;padding:14px 8px;border-radius:12px;text-align:center;border-top:3px solid #06b6d4;">
        <div style="font-size:24px;font-weight:bold;color:#06b6d4;">${completed}</div>
        <div style="font-size:11px;color:#94a3b8;">✔️ Completed</div>
      </div>
      <div style="flex:1;min-width:80px;background:#0f172a;padding:14px 8px;border-radius:12px;text-align:center;border-top:3px solid #a78bfa;">
        <div style="font-size:24px;font-weight:bold;color:#a78bfa;">${pending}</div>
        <div style="font-size:11px;color:#94a3b8;">⏳ Pending</div>
      </div>
    </div>

    <!-- ONBOARDING BAR CHART -->
    ${bar(active, '#7ed321', '✅ Active', maxOnboard)}
    ${bar(inProgress, '#f5a623', '🚀 In Progress', maxOnboard)}
    ${bar(completed, '#06b6d4', '✔️ Completed', maxOnboard)}
    ${bar(pending, '#a78bfa', '⏳ Pending', maxOnboard)}

    <!-- DISTRIBUTION -->
    <div style="margin-top:16px;">
      <div style="display:flex;height:24px;border-radius:6px;overflow:hidden;gap:2px;">
        <div style="width:${pct(active,total)}%;background:#7ed321;"></div>
        <div style="width:${pct(inProgress,total)}%;background:#f5a623;"></div>
        <div style="width:${pct(completed,total)}%;background:#06b6d4;"></div>
        <div style="width:${pct(pending,total)}%;background:#a78bfa;"></div>
      </div>
      <div style="display:flex;gap:12px;margin-top:8px;font-size:11px;color:#94a3b8;flex-wrap:wrap;">
        <span>🟢 Active ${pct(active,total)}%</span>
        <span>🟡 In Progress ${pct(inProgress,total)}%</span>
        <span>🔵 Completed ${pct(completed,total)}%</span>
        <span>🟣 Pending ${pct(pending,total)}%</span>
      </div>
    </div>
  </div>

  <!-- ========== SECTION 2: GRIEVANCE ========== -->
  <div style="background:#1e293b;padding:20px;border-radius:16px;margin-bottom:20px;border-left:4px solid #f5a623;">
    <h2 style="margin:0 0 16px;font-size:16px;color:#f5a623;">⚠️ Grievance Overview</h2>

    <!-- KPI -->
    <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:18px;">
      <div style="flex:1;min-width:80px;background:#0f172a;padding:14px 8px;border-radius:12px;text-align:center;border-top:3px solid #f5a623;">
        <div style="font-size:24px;font-weight:bold;color:#f5a623;">${grievanceYes}</div>
        <div style="font-size:11px;color:#94a3b8;">⚠️ Grievances</div>
      </div>
      <div style="flex:1;min-width:80px;background:#0f172a;padding:14px 8px;border-radius:12px;text-align:center;border-top:3px solid #7ed321;">
        <div style="font-size:24px;font-weight:bold;color:#7ed321;">${grievanceNo}</div>
        <div style="font-size:11px;color:#94a3b8;">✅ No Issue</div>
      </div>
      <div style="flex:1;min-width:80px;background:#0f172a;padding:14px 8px;border-radius:12px;text-align:center;border-top:3px solid #ff4d4d;">
        <div style="font-size:24px;font-weight:bold;color:#ff4d4d;">${openIssues}</div>
        <div style="font-size:11px;color:#94a3b8;">🔓 Open</div>
      </div>
      <div style="flex:1;min-width:80px;background:#0f172a;padding:14px 8px;border-radius:12px;text-align:center;border-top:3px solid #06b6d4;">
        <div style="font-size:24px;font-weight:bold;color:#06b6d4;">${closedIssues}</div>
        <div style="font-size:11px;color:#94a3b8;">🔒 Closed</div>
      </div>
    </div>

    <!-- GRIEVANCE BAR -->
    ${bar(grievanceYes, '#f5a623', '⚠️ Has Grievance', maxGriev)}
    ${bar(openIssues, '#ff4d4d', '🔓 Open Issues', maxGriev)}
    ${bar(closedIssues, '#06b6d4', '🔒 Closed Issues', maxGriev)}

    <!-- PRIORITY CARDS -->
    <div style="display:flex;gap:12px;margin-top:18px;">
      <div style="flex:1;background:#ff4d4d22;border:1px solid #ff4d4d;padding:14px;border-radius:10px;text-align:center;">
        <div style="font-size:22px;font-weight:bold;color:#ff4d4d;">${highP}</div>
        <div style="font-size:12px;color:#94a3b8;margin-top:4px;">🔴 High</div>
      </div>
      <div style="flex:1;background:#f5a62322;border:1px solid #f5a623;padding:14px;border-radius:10px;text-align:center;">
        <div style="font-size:22px;font-weight:bold;color:#f5a623;">${mediumP}</div>
        <div style="font-size:12px;color:#94a3b8;margin-top:4px;">🟡 Medium</div>
      </div>
      <div style="flex:1;background:#7ed32122;border:1px solid #7ed321;padding:14px;border-radius:10px;text-align:center;">
        <div style="font-size:22px;font-weight:bold;color:#7ed321;">${lowP}</div>
        <div style="font-size:12px;color:#94a3b8;margin-top:4px;">🟢 Low</div>
      </div>
    </div>

    <!-- ISSUE TYPE TABLE -->
    <h3 style="margin:20px 0 12px;font-size:14px;color:#e2e8f0;">📋 Issue Type × Priority</h3>
    <table style="width:100%;border-collapse:collapse;">
      <tr style="background:#0f172a;">
        <th style="padding:9px 12px;text-align:left;font-size:11px;color:#64748b;text-transform:uppercase;">Issue Type</th>
        <th style="padding:9px 12px;text-align:center;font-size:11px;color:#ff4d4d;text-transform:uppercase;">🔴 High</th>
        <th style="padding:9px 12px;text-align:center;font-size:11px;color:#f5a623;text-transform:uppercase;">🟡 Medium</th>
        <th style="padding:9px 12px;text-align:center;font-size:11px;color:#7ed321;text-transform:uppercase;">🟢 Low</th>
        <th style="padding:9px 12px;text-align:center;font-size:11px;color:#94a3b8;text-transform:uppercase;">Total</th>
      </tr>
      ${issueRows}
    </table>
  </div>

  <!-- ========== SECTION 3: DEPARTMENT TABLE ========== -->
  <div style="background:#1e293b;padding:20px;border-radius:16px;margin-bottom:20px;border-left:4px solid #a78bfa;">
    <h2 style="margin:0 0 16px;font-size:16px;color:#a78bfa;">🏢 Department Breakdown</h2>
    <table style="width:100%;border-collapse:collapse;">
      <tr style="background:#0f172a;">
        <th style="padding:9px 10px;text-align:left;font-size:11px;color:#64748b;text-transform:uppercase;">Dept</th>
        <th style="padding:9px 10px;text-align:center;font-size:11px;color:#00c6ff;text-transform:uppercase;">Total</th>
        <th style="padding:9px 10px;text-align:center;font-size:11px;color:#7ed321;text-transform:uppercase;">Active</th>
        <th style="padding:9px 10px;text-align:center;font-size:11px;color:#f5a623;text-transform:uppercase;">Onboard</th>
        <th style="padding:9px 10px;text-align:center;font-size:11px;color:#06b6d4;text-transform:uppercase;">Done</th>
        <th style="padding:9px 10px;text-align:center;font-size:11px;color:#ff4d4d;text-transform:uppercase;">Grievance</th>
      </tr>
      ${deptRows}
    </table>
  </div>

  <!-- CTA -->
  <div style="text-align:center;margin-top:20px;">
    <a href="${dashboardLink}"
       style="background:linear-gradient(135deg,#00c6ff,#7f00ff);color:white;
              padding:14px 35px;text-decoration:none;border-radius:10px;
              font-weight:bold;font-size:15px;">
      📋 View Full Sheet
    </a>
  </div>

  <p style="text-align:center;font-size:11px;color:#475569;margin-top:20px;">
    PeopleOS • Auto-generated by n8n • ${new Date().toLocaleString('en-IN')}
  </p>
</div>`;

return [{ json: { htmlEmail: html } }];
